import React from 'react';

/**
 * Organizo logo — stylized "O" in a circle. Uses currentColor so it adapts to navbar/footer.
 */
export default function OrganizoLogo({ className = '', size = 32 }) {
  return (
    <svg
      className={className}
      width={size}
      height={size}
      viewBox="0 0 40 40"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <circle cx="20" cy="20" r="18" stroke="currentColor" strokeWidth="3" fill="none" />
      <circle cx="20" cy="20" r="10" stroke="currentColor" strokeWidth="2.5" fill="none" />
    </svg>
  );
}
